import{_ as t,o as a,c as o,a5 as r}from"./chunks/framework.B4rbIdlB.js";const m=JSON.parse('{"title":"IAM UI","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/iam-ui.md","filePath":"reference/components/iam-ui.md"}'),n={name:"reference/components/iam-ui.md"};function i(d,e,s,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="iam-ui" tabindex="-1">IAM UI <a class="header-anchor" href="#iam-ui" aria-label="Permalink to &quot;IAM UI&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The <strong>IAM UI</strong> is the identity and access management microfrontend for Platform Mesh. It provides user and role management directly inside the Portal shell, giving workspace administrators full control over who can access a resource and with what permissions.</p><p>The key capabilities are:</p><ul><li><strong>Browse members</strong> — paginated, searchable, and filterable list of all users assigned to a resource</li><li><strong>Add members</strong> — invite existing platform users or send email invitations to new users, assigning one or more roles in a single step</li><li><strong>Assign and remove roles</strong> — update role assignments inline; at least one owner is always enforced</li><li><strong>Leave a scope</strong> — a user can remove themselves from a resource they belong to</li></ul><h2 id="runtime-role" tabindex="-1">Runtime role <a class="header-anchor" href="#runtime-role" aria-label="Permalink to &quot;Runtime role&quot;">​</a></h2><p>IAM UI calls the <a href="./iam-service.html">IAM service</a> via GraphQL to read and write authorization state. It surfaces as two independently deployable artifacts inside the Portal:</p><ul><li><strong>Standalone UI</strong> — a full-page Angular microfrontend loaded by Luigi inside an iframe, mounted at <code>/ui/iam/ui/</code>. It handles the members listing page (<code>/:entityId/members</code>) and the add-members flow (<code>/:entityId/add-members</code>).</li><li><strong>Web components</strong> — self-registering custom elements loaded by Luigi as ES modules, mounted at <code>/ui/iam/wc/</code>. These embed lightweight member views (e.g. a <code>members-sidebar</code>) into compound layout slots without a full iframe.</li></ul><p>Both artifacts read their runtime context (IAM service URL, tenant, entity, and KCP workspace path) from the Luigi <code>globalContext</code>, so they require no static configuration.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Luigi globalContext</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>IAM UI (iframe or web component)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>GraphQL (Apollo) → IAM service</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>OpenFGA tuple evaluation + Keycloak user enrichment</span></span></code></pre></div><p><strong>Luigi navigation nodes</strong> registered by the UI:</p><table tabindex="0"><thead><tr><th>PathSegment</th><th>EntityType</th><th>Visibility</th><th>Purpose</th></tr></thead><tbody><tr><td><code>members</code></td><td><code>project/team</code></td><td>Visible (order 3)</td><td>Members listing page</td></tr><tr><td><code>add-members</code></td><td><code>project/team</code></td><td>Hidden</td><td>Add-members dialog</td></tr><tr><td><code>members-sidebar</code></td><td><code>project.overview::compound</code></td><td>Sidebar slot (order 10)</td><td>Members sidebar web component</td></tr></tbody></table><h2 id="technology-stack" tabindex="-1">Technology stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Technology</th></tr></thead><tbody><tr><td>Framework</td><td>Angular 21</td></tr><tr><td>UI Components</td><td>SAP Fundamental NGX 0.61</td></tr><tr><td>Micro-frontend orchestration</td><td>Luigi 2.25</td></tr><tr><td>GraphQL client</td><td>Apollo Angular 13 / Apollo Client 4</td></tr><tr><td>Subscriptions transport</td><td>SSE (Server-Sent Events)</td></tr><tr><td>Testing</td><td>Vitest 4</td></tr><tr><td>Language</td><td>TypeScript (ES2022, strict mode)</td></tr><tr><td>Container</td><td>nginx:alpine, served on port 8080</td></tr></tbody></table><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li><a href="https://github.com/platform-mesh/iam-ui" target="_blank" rel="noreferrer">github.com/platform-mesh/iam-ui</a></li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>The UI reads all runtime configuration from the Luigi node context injected by the Portal. No static environment files are required in production. The relevant context fields are:</p><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th></tr></thead><tbody><tr><td><code>portalContext.iamServiceApiUrl</code></td><td>GraphQL endpoint for the IAM service</td></tr><tr><td><code>portalContext.avatarImgUrl</code></td><td>Base URL for user avatar images</td></tr><tr><td><code>tenantId</code></td><td>Tenant scope for multi-tenant deployments</td></tr><tr><td><code>entityType</code> / <code>entityId</code></td><td>The resource being administered</td></tr><tr><td><code>resourceDefinition</code></td><td>Kubernetes resource metadata (group, kind, scope, namespace)</td></tr><tr><td><code>kcpPath</code></td><td>KCP workspace path for multi-cluster routing</td></tr><tr><td><code>analyticsTrackerConfig</code></td><td>Optional Matomo analytics configuration</td></tr></tbody></table><p>For local development, copy <code>.env-example</code> to <code>.env</code> and populate the required values before running.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./iam-service.html">IAM service</a></li><li><a href="./portal.html">Portal</a></li><li><a href="./keycloak.html">Keycloak</a></li><li><a href="/pr-preview/pr-126/concepts/identity-and-authorization.html">Identity and authorization</a></li></ul>`,22)])])}const u=t(n,[["render",i]]);export{m as __pageData,u as default};
